protocol ZoneManagerCollectorDelegate: AnyObject {
    func collector(_ collector: ZoneManagerCollector, didLog state: ZoneManagerState)
    func collector(_ collector: ZoneManagerCollector, didCollect event: ZoneManagerEvent)
}

protocol ZoneManagerCollector: CLLocationManagerDelegate {
    var delegate: ZoneManagerCollectorDelegate? { get set }
    func ignoreNextState(for region: CLRegion)
}

class ZoneManagerCollectorImpl: NSObject, ZoneManagerCollector {
    weak var delegate: ZoneManagerCollectorDelegate?

    private var ignoredNextRegions = Set<CLRegion>()

    func ignoreNextState(for region: CLRegion) {
        ignoredNextRegions.insert(region)
    }

    func locationManager(
        _ manager: CLLocationManager,
        didFailWithError error: Error
    ) {
        delegate?.collector(self, didLog: .didError(error))
    }

    func locationManager(
        _ manager: CLLocationManager,
        monitoringDidFailFor region: CLRegion?,
        withError error: Error
    ) {
        delegate?.collector(self, didLog: .didFailMonitoring(region, error))
    }

    func locationManager(
        _ manager: CLLocationManager,
        didStartMonitoringFor region: CLRegion
    ) {
        delegate?.collector(self, didLog: .didStartMonitoring(region))
    }

    func locationManager(
        _ manager: CLLocationManager,
        didDetermineState state: CLRegionState,
        for region: CLRegion
    ) {
        guard !ignoredNextRegions.contains(region) else {
            ignoredNextRegions.remove(region)
            return
        }

        let zone = Current.realm()
            .objects(RLMZone.self)
            .first(where: {
                $0.identifier == region.identifier ||
                    $0.identifier == region.identifier.components(separatedBy: "@").first
            })

        let event = ZoneManagerEvent(
            eventType: .region(region, state),
            associatedZone: zone
        )

        delegate?.collector(self, didCollect: event)
    }

    func locationManager(
        _ manager: CLLocationManager,
        didUpdateLocations locations: [CLLocation]
    ) {
        let event = ZoneManagerEvent(
            eventType: .locationChange(locations)
        )

        delegate?.collector(self, didCollect: event)
    }
}

import Foundation

public class PerServerContainer<ObjectType>: ServerObserver {
    public struct Value {
        public var object: ObjectType
        public var destructor: Destructor?

        public init(_ object: ObjectType, destructor: Destructor? = nil) {
            self.object = object
            self.destructor = destructor
        }
    }

    public typealias Constructor = (Server) -> Value
    public typealias Destructor = (Identifier<Server>, ObjectType) -> Void

    private var lazy: Bool
    public var constructor: Constructor {
        didSet {
            destruct(from: backing, to: [:])
            createAll()
        }
    }

    private var backing = [Identifier<Server>: Value]() {
        willSet {
            destruct(from: backing, to: newValue)
        }
    }

    public init(lazy: Bool = false, constructor: @escaping Constructor) {
        self.constructor = constructor
        self.lazy = lazy
        Current.servers.add(observer: self)
        createAll()
    }

    deinit {
        destruct(from: backing, to: [:])
    }

    public subscript(_ server: Server) -> ObjectType {
        if let value = backing[server.identifier] {
            return value.object
        } else {
            let value = constructor(server)
            backing[server.identifier] = value
            return value.object
        }
    }

    private func destruct(from: [Identifier<Server>: Value], to: [Identifier<Server>: Value]) {
        for (key, value) in from where to[key] == nil {
            value.destructor?(key, value.object)
        }
    }

    private func createAll() {
        guard !lazy else { return }
        for server in Current.servers.all {
            backing[server.identifier] = constructor(server)
        }
    }

    public func serversDidChange(_ serverManager: ServerManager) {
        let existing = Set(backing.keys)
        let servers = Current.servers.all

        let deleted = existing.subtracting(servers.map(\.identifier))
        let needed = servers.filter { !existing.contains($0.identifier) }

        backing = deleted.reduce(into: backing) { result, identifier in
            result[identifier] = nil
        }

        if !lazy {
            backing = needed.reduce(into: backing) { result, server in
                result[server.identifier] = constructor(server)
            }
        }
    }
}

